import{_ as i,o,c as n,ae as a}from"./chunks/framework.BD9pLfSD.js";const u=JSON.parse('{"title":"Technical Design: Noir-ShadowWire Binding (Nullifier-as-Nonce)","description":"","frontmatter":{},"headers":[],"relativePath":"docs/research/2026-01-21-noir-shadowwire-binding.md","filePath":"docs/research/2026-01-21-noir-shadowwire-binding.md"}'),t={name:"docs/research/2026-01-21-noir-shadowwire-binding.md"};function r(c,e,l,d,s,h){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="technical-design-noir-shadowwire-binding-nullifier-as-nonce" tabindex="-1">Technical Design: Noir-ShadowWire Binding (Nullifier-as-Nonce) <a class="header-anchor" href="#technical-design-noir-shadowwire-binding-nullifier-as-nonce" aria-label="Permalink to &quot;Technical Design: Noir-ShadowWire Binding (Nullifier-as-Nonce)&quot;">​</a></h1><h2 id="objective" tabindex="-1">Objective <a class="header-anchor" href="#objective" aria-label="Permalink to &quot;Objective&quot;">​</a></h2><p>Establish a cryptographic link between the Agent&#39;s Identity (Noir) and the Financial Transaction (ShadowWire) to prevent &quot;Proof Replay&quot; and &quot;Transaction Decoupling&quot; attacks.</p><h2 id="the-concept" tabindex="-1">The Concept <a class="header-anchor" href="#the-concept" aria-label="Permalink to &quot;The Concept&quot;">​</a></h2><p>Use the <code>nullifier</code> generated by the Noir circuit as the source of truth for the <code>nonce</code> in the ShadowWire transfer.</p><h2 id="data-mapping-transformation" tabindex="-1">Data Mapping &amp; Transformation <a class="header-anchor" href="#data-mapping-transformation" aria-label="Permalink to &quot;Data Mapping &amp; Transformation&quot;">​</a></h2><p>Since Noir nullifiers are 254-bit fields and ShadowWire nonces are typically 64-bit integers (u64):</p><ol><li><p><strong>Agent Side (SDK):</strong></p><ul><li>Generate Noir Proof -&gt; Extract <code>nullifier</code> (32 bytes).</li><li>Derive <code>sw_nonce</code> = <code>Keccak256(nullifier)[0..8]</code> (First 8 bytes as a Little Endian u64).</li><li>Call <code>shadowwire.uploadProof(nonce: sw_nonce, ...)</code>.</li></ul></li><li><p><strong>On-Chain Side (Gateway):</strong></p><ul><li>Receive <code>ProofPayload</code> (containing the 32-byte Noir nullifier).</li><li>Receive <code>sw_proof_pda</code> (ShadowWire&#39;s commitment account).</li><li><strong>Validation Step 1:</strong> Verify Noir proof and record/check the 32-byte nullifier PDA.</li><li><strong>Validation Step 2:</strong><ul><li>Calculate <code>derived_nonce</code> = <code>Keccak256(noir_nullifier)[0..8]</code>.</li><li>Load <code>sw_proof_pda</code> data.</li><li>Assert <code>sw_proof_pda.nonce == derived_nonce</code>.</li></ul></li></ul></li></ol><h2 id="success-metrics" tabindex="-1">Success Metrics <a class="header-anchor" href="#success-metrics" aria-label="Permalink to &quot;Success Metrics&quot;">​</a></h2><ul><li><strong>Atomicity:</strong> A ShadowWire payment cannot be reused for a different Noir identity proof.</li><li><strong>Double-Spending Prevention:</strong> The Noir nullifier PDA prevents the same identity from acting twice, while ShadowWire&#39;s internal logic prevents the money from being spent twice.</li><li><strong>Auditor Visibility:</strong> An auditor can verify the link without knowing the Agent&#39;s secret.</li></ul><h2 id="implementation-tasks-completed-2026-01-21" tabindex="-1">Implementation Tasks (Completed 2026-01-21) <a class="header-anchor" href="#implementation-tasks-completed-2026-01-21" aria-label="Permalink to &quot;Implementation Tasks (Completed 2026-01-21)&quot;">​</a></h2><ul><li>[x] <strong>SDK:</strong> Update <code>ShadowWireAdapter</code> to accept a <code>nullifier</code> seed for nonce derivation.</li><li>[x] <strong>Gateway:</strong> Update <code>VerifyBadge</code> instruction to include the ShadowWire Proof PDA account.</li><li>[x] <strong>Gateway:</strong> Implement the <code>derived_nonce</code> check in <code>processor.rs</code>.</li></ul>',12)])])}const f=i(t,[["render",r]]);export{u as __pageData,f as default};
